9	const PROCESSING_FEE = 5;
10	const NEWCOMER_PER_ITEM_SURCHARGE_RATE = 0.1;
11	
12	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	};
18	
19	const basePremiumForItem = (item: Item): number =>
20	  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
21	
22	const isNewcomer = (customer: Customer): boolean =>
23	  customer.yearsWithMHPCO === 0;
24	
25	const premiumForItem = (item: Item, customer: Customer): number => {
26	  const base = basePremiumForItem(item);
27	  const surcharge = isNewcomer(customer) ? base * NEWCOMER_PER_ITEM_SURCHARGE_RATE : 0;
28	  return base + surcharge;
29	};
30	
31	export const quote = (input: QuoteInput): { premium: number } => {
32	  const itemsTotal = input.items.reduce(
33	    (sum, item) => sum + premiumForItem(item, input.customer),
34	    0,
35	  );
36	  return { premium: itemsTotal + PROCESSING_FEE };
37	};
38	
39	export const claim = (_input: unknown): unknown => {
40	  return undefined;
41	};
